import{_ as o,o as r,c as e,ag as l}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Cursor 配置","description":"","frontmatter":{},"headers":[],"relativePath":"tools/cursor.md","filePath":"tools/cursor.md"}'),t={name:"tools/cursor.md"};function i(s,a,u,n,d,h){return r(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="cursor-配置" tabindex="-1">Cursor 配置 <a class="header-anchor" href="#cursor-配置" aria-label="Permalink to &quot;Cursor 配置&quot;">​</a></h1><p>Cursor 是一个 AI 代码编辑器，基于 VS Code 构建，内置 AI 功能。</p><h2 id="这是什么工具" tabindex="-1">这是什么工具 <a class="header-anchor" href="#这是什么工具" aria-label="Permalink to &quot;这是什么工具&quot;">​</a></h2><p>Cursor 是一个独立的代码编辑器，内置 AI 编程助手功能。它支持多种 AI Provider。</p><h2 id="配置前需要准备什么" tabindex="-1">配置前需要准备什么 <a class="header-anchor" href="#配置前需要准备什么" aria-label="Permalink to &quot;配置前需要准备什么&quot;">​</a></h2><ul><li>有效的 API Key</li><li>默认 Base URL：<code>https://api.1010101.asia/</code></li></ul><h2 id="从哪里打开配置入口" tabindex="-1">从哪里打开配置入口 <a class="header-anchor" href="#从哪里打开配置入口" aria-label="Permalink to &quot;从哪里打开配置入口&quot;">​</a></h2><p>Cursor 的自定义 Base URL 配置入口可能因版本而异。常见入口：</p><ol><li>打开 Cursor</li><li>进入设置（<code>Ctrl/Cmd + ,</code>）</li><li>查找&quot;AI&quot;或&quot;Model&quot;相关设置</li></ol><p>或：</p><ol><li>打开命令面板（<code>Ctrl/Cmd + Shift + P</code>）</li><li>搜索&quot;AI Settings&quot;或&quot;Model Settings&quot;</li></ol><p><strong>注意</strong>：Cursor 的公开文档对自定义 Base URL 的说明较少，建议在应用内查找相关设置，或参考社区文档。</p><h2 id="最短完整配置步骤" tabindex="-1">最短完整配置步骤 <a class="header-anchor" href="#最短完整配置步骤" aria-label="Permalink to &quot;最短完整配置步骤&quot;">​</a></h2><p>由于 Cursor 的公开文档对自定义 Base URL 配置说明有限，以下为通用步骤：</p><ol><li>在设置中找到&quot;AI Provider&quot;或&quot;Model Provider&quot;选项</li><li>选择&quot;Custom&quot;或&quot;OpenAI Compatible&quot;</li><li>在 <code>API Key</code> 字段中输入你的 API Key</li><li>在 <code>Base URL</code> 字段中输入：<code>https://api.1010101.asia/</code></li><li>保存设置</li></ol><h2 id="配置示例" tabindex="-1">配置示例 <a class="header-anchor" href="#配置示例" aria-label="Permalink to &quot;配置示例&quot;">​</a></h2><h3 id="可能的设置字段" tabindex="-1">可能的设置字段 <a class="header-anchor" href="#可能的设置字段" aria-label="Permalink to &quot;可能的设置字段&quot;">​</a></h3><ul><li><strong>Provider</strong>: Custom 或 OpenAI Compatible</li><li><strong>API Key</strong>: <code>sk-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</code></li><li><strong>Base URL</strong>: <code>https://api.1010101.asia/</code></li><li><strong>Model</strong>: <code>gpt-4</code>（如需要）</li></ul><h2 id="如何验证生效" tabindex="-1">如何验证生效 <a class="header-anchor" href="#如何验证生效" aria-label="Permalink to &quot;如何验证生效&quot;">​</a></h2><ol><li>在 Cursor 中打开一个文件</li><li>使用 AI 功能（如 <code>Ctrl/Cmd + K</code>）</li><li>发送一个简单请求</li><li>如果收到正常回复，说明配置成功</li></ol><h2 id="常见报错与排查" tabindex="-1">常见报错与排查 <a class="header-anchor" href="#常见报错与排查" aria-label="Permalink to &quot;常见报错与排查&quot;">​</a></h2><h3 id="_401-unauthorized" tabindex="-1">401 Unauthorized <a class="header-anchor" href="#_401-unauthorized" aria-label="Permalink to &quot;401 Unauthorized&quot;">​</a></h3><p><strong>原因</strong>：API Key 错误或无效</p><p><strong>排查</strong>：</p><ul><li>检查 API Key 是否正确</li><li>检查 API Key 是否有多余空格</li><li>确认 API Key 是否已过期或被撤销</li></ul><h3 id="_404-not-found" tabindex="-1">404 Not Found <a class="header-anchor" href="#_404-not-found" aria-label="Permalink to &quot;404 Not Found&quot;">​</a></h3><p><strong>原因</strong>：Base URL 错误</p><p><strong>排查</strong>：</p><ul><li>检查 Base URL 是否正确</li><li>确认 Base URL 格式符合要求</li><li>检查网络连接是否正常</li></ul><h3 id="设置中找不到-base-url-选项" tabindex="-1">设置中找不到 Base URL 选项 <a class="header-anchor" href="#设置中找不到-base-url-选项" aria-label="Permalink to &quot;设置中找不到 Base URL 选项&quot;">​</a></h3><p><strong>原因</strong>：Cursor 版本或界面变化</p><p><strong>排查</strong>：</p><ul><li>尝试在命令面板中搜索相关设置</li><li>查看 Cursor 官方文档或社区论坛</li><li>确认当前 Cursor 版本是否支持自定义 Base URL</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="文档不完整" tabindex="-1">文档不完整 <a class="header-anchor" href="#文档不完整" aria-label="Permalink to &quot;文档不完整&quot;">​</a></h3><p>Cursor 的公开文档对自定义 Base URL 的说明较少。建议：</p><ul><li>在应用内仔细查找相关设置</li><li>参考 Cursor 社区或论坛</li><li>关注 Cursor 官方文档更新</li></ul><h3 id="版本差异" tabindex="-1">版本差异 <a class="header-anchor" href="#版本差异" aria-label="Permalink to &quot;版本差异&quot;">​</a></h3><p>Cursor 的设置界面可能因版本更新而变化。本页面基于 2026 年 5 月的信息，如有变化请以应用内实际界面为准。</p><h3 id="模型选择" tabindex="-1">模型选择 <a class="header-anchor" href="#模型选择" aria-label="Permalink to &quot;模型选择&quot;">​</a></h3><p>Cursor 可能要求选择模型。请根据服务商文档确认正确的模型名。</p><h3 id="byok-功能" tabindex="-1">BYOK 功能 <a class="header-anchor" href="#byok-功能" aria-label="Permalink to &quot;BYOK 功能&quot;">​</a></h3><p>Cursor 可能提供 BYOK（Bring Your Own Key）功能，允许使用自定义 API Key 和 Base URL。详情请参考 Cursor 官方文档。</p>',43)])])}const x=o(t,[["render",i]]);export{p as __pageData,x as default};
